// CSD_RATIONALE_BEGIN
// This CSD strategy generates a response that starts with a prefix, followed by a Prover9-style logical formula enclosed in " << " and " >> ". The strategy uses constrained steps to ensure the logical formula adheres to the grammar, respecting the delimiter tokens.
// CSD_RATIONALE_END

generated := [];

while stepsLeft > 0 && !parser.IsCompletePrefix(generated)
  invariant lm.ValidTokensIdsLogits()
  invariant parser.IsValidPrefix(generated)
  invariant 0 <= stepsLeft <= maxSteps
  invariant |generated| + stepsLeft == maxSteps
  decreases stepsLeft
{
  helpers.RollbackToValidPrefix(parser, generated);

  // Check if the prompt contains a logical formula within the delimiter tokens
  var hasLogicalFormula := false;
  for i in 0 .. |prompt| - 1 {
    if (prompt[i] == LeftDelimiter && prompt[i + 1] == 'f') {
      hasLogicalFormula := true;
      break;
    }
  }

  if hasLogicalFormula {
    // Use ConstrainedStep to generate the logical formula
    var next, newSteps := helpers.ConstrainedStep(lm, parser, prompt, generated, stepsLeft);
    generated := generated + [next];
    stepsLeft := newSteps;
  } else {
    // Use UnconstrainedStep to generate plain text
    var next, newSteps := helpers.UnconstrainedStep(lm, prompt, generated, stepsLeft);
    generated := generated + [next];
    stepsLeft := newSteps;
  }
}

